const startTime = Date.now();
const item = $input.first().json;

// Dados da resposta
const statusCode = item.statusCode || 0;
const body = item.body || '';
const headers = item.headers || {};
const error = item.error || null;

// Calcula tempo de resposta
const responseTime = Date.now() - startTime;

// Validações
const isUp = statusCode >= 200 && statusCode < 400;
const isFast = responseTime < 2000;
const hasBody = typeof body === 'string' ? body.length > 0 : Object.keys(body).length > 0;

// Status geral
const healthy = isUp && isFast && hasBody;

return [{
  json: {
    timestamp: new Date().toISOString(),
    endpoint: 'https://teste.com.br/teste',
    statusCode,
    responseTimeMs: responseTime,
    bodySize: typeof body === 'string' ? body.length : JSON.stringify(body).length,
    checks: {
      isUp,
      isFast,
      hasBody
    },
    healthy,
    error: error ? error.message || String(error) : null
  }
}];

const data = $input.first().json;

const log = {
  ...data,
  status: 'OK',
  message: `✅ API saudável | Status: ${data.statusCode} | Tempo: ${data.responseTimeMs}ms`
};

console.log(log.message);

return [{ json: log }];

const data = $input.first().json;

const failures = [];
if (!data.checks.isUp) failures.push(`Status ${data.statusCode} (esperado 2xx)`);
if (!data.checks.isFast) failures.push(`Lento: ${data.responseTimeMs}ms (limite: 2000ms)`);
if (!data.checks.hasBody) failures.push('Corpo vazio');
if (data.error) failures.push(`Erro: ${data.error}`);

const alert = {
  ...data,
  status: 'FALHA',
  failures,
  message: `🚨 ALERTA - teste.com.br/teste\n\nStatus: ${data.statusCode}\nTempo: ${data.responseTimeMs}ms\nProblemas:\n${failures.map(f => `  • ${f}`).join('\n')}\n\nTimestamp: ${data.timestamp}`
};

console.log(alert.message);

return [{ json: alert }];
